function renderProjects() {
    const grid = document.getElementById('projects-grid');
    if (!grid)
        return;
    projects.forEach(p => {
        const card = document.createElement('div');
        card.className = 'project-card fade-up';
        const logoHtml = p.logo
            ? `<img src="${p.logo}" alt="${p.name}" class="project-logo">`
            : `<div class="project-logo" style="width:52px;height:52px;border-radius:12px;background:var(--accent-light);display:flex;align-items:center;justify-content:center;font-size:1.2rem;font-weight:700;color:var(--accent)">${p.name.charAt(0)}</div>`;
        const statusLabel = p.status === 'live' ? 'Live' : 'Currently in Development';
        const externalLinks = p.detail.links.map(l => `<a href="${l.href}" target="_blank" class="btn-${l.type}">${l.label}</a>`).join('');
        card.innerHTML = `
            ${logoHtml}
            <div class="project-status ${p.status}">${statusLabel}</div>
            <h3>${p.name}</h3>
            <p class="project-description">${p.tagline}</p>
            <div class="project-actions">
                <button class="btn-primary" onclick="openModal('${p.id}')">Details</button>
                ${externalLinks}
            </div>
        `;
        grid.appendChild(card);
    });
}
function openModal(id) {
    const project = projects.find(p => p.id === id);
    if (!project)
        return;
    const overlay = document.getElementById('modal-overlay');
    const content = document.getElementById('modal-content');
    const linksHtml = project.detail.links.length
        ? `<div class="modal-links">${project.detail.links.map(l => `<a href="${l.href}" target="_blank" class="btn-${l.type}">${l.label}</a>`).join('')}</div>`
        : '';
    const techHtml = project.detail.tech.length
        ? `<p class="modal-section-title">Stack</p>
           <div class="modal-tech-list">${project.detail.tech.map(t => `<span class="tech-tag">${t}</span>`).join('')}</div>`
        : '';
    const screenshotsHtml = project.detail.screenshots.length
        ? `<p class="modal-section-title">Screenshots</p>
           <div class="modal-screenshots">${project.detail.screenshots.map(s => `<img src="${s}" alt="Screenshot">`).join('')}</div>`
        : '';
    const statusLabel = project.status === 'live' ? 'Live' : 'In Entwicklung';
    content.innerHTML = `
        <span class="modal-eyebrow">${statusLabel}</span>
        <h2>${project.name}</h2>
        ${linksHtml}
        <p class="modal-desc" style="white-space:pre-line">${project.detail.description}</p>
        ${techHtml}
        ${screenshotsHtml}
    `;
    overlay.classList.add('open');
    document.body.style.overflow = 'hidden';
}
function closeModal() {
    const overlay = document.getElementById('modal-overlay');
    overlay.classList.remove('open');
    document.body.style.overflow = '';
}
document.addEventListener('DOMContentLoaded', () => {
    renderProjects();
    const closeBtn = document.getElementById('modal-close');
    const overlay = document.getElementById('modal-overlay');
    closeBtn === null || closeBtn === void 0 ? void 0 : closeBtn.addEventListener('click', closeModal);
    overlay.addEventListener('click', (e) => {
        if (e.target === overlay)
            closeModal();
    });
    document.addEventListener('keydown', (e) => {
        if (e.key === 'Escape')
            closeModal();
    });
});
